+        resolutions: ["1K", "2K", "4K"],
+      },
+    },
+    generateImage: async (req) => (await loadGoogleImageGenerationProvider()).generateImage(req),
+  };
+}
+
+function createLazyGoogleMediaUnderstandingProvider(): MediaUnderstandingProvider {
